  "pattern": {
    "name": "factor_outer_logical_select_with_inner_false_arm_select",
    "summary": "Match an outer select whose condition is a logical combination of an inner select's condition and some alternate condition, and whose false/true arm is itself a select on that same inner condition. Reassociate the decision tree so the alternate condition is tested first and the shared inner condition is sunk into a simpler nested select.",
    "source_shape": [
      "inner = select tc, X, Y",
      "outer.cond = logical(tc, ta)  ; any equivalent and/or form, including boolean select encodings",
      "outer = select outer.cond, T, inner"
    ],
    "generalized_forms": {
      "and_family": {
        "canonical_source": [
          "inner = select tc, X, Y",
          "outer = select (tc && ta), T, inner"
        ],
        "canonical_result": [
          "tmp = select ta, T, X",
          "result = select tc, tmp, Y"
        ],
        "equivalent_truth_table": {
          "tc=false": "outer.cond is false, so result = inner.false = Y",
          "tc=true": "outer.cond reduces to ta, so result = select ta, T, X"
        }
      },
      "or_family": {
        "canonical_source": [
          "inner = select tc, X, Y",
          "outer = select (tc || ta), inner, F"
        ],
