          "tmp = select ta, Y, F",
          "result = select tc, X, tmp"
        ],
        "equivalent_truth_table": {
          "tc=true": "outer.cond is true, so result = inner.true = X",
          "tc=false": "outer.cond reduces to ta, so result = select ta, Y, F"
        }
      }
    },
